function redeemCoupon(userCouponCode) {
  const coupon = coupons.find(coupon => coupon.code === userCouponCode);

  if (!coupon) {
    return "Invalid coupon code";
  }

  if (!coupon.isValid()) {
    return "Coupon is expired or already used";
  }

  coupon.markAsUsed();
  return `Coupon successfully redeemed. Discount applied: ${coupon.discount}%`;
}

